-- Step 18: load [residents]
SET XACT_ABORT ON;
BEGIN TRAN;
IF OBJECT_ID(N'dbo.residents', N'U') IS NOT NULL
BEGIN
  IF EXISTS (SELECT 1 FROM sys.identity_columns WHERE object_id = OBJECT_ID(N'dbo.residents')) SET IDENTITY_INSERT dbo.residents ON;
  IF EXISTS (SELECT 1 FROM sys.identity_columns WHERE object_id = OBJECT_ID(N'dbo.residents')) SET IDENTITY_INSERT dbo.residents OFF;
END
COMMIT;
